import React from "react";
import { Link } from "react-router-dom";

function Sidebar() {

  const role = localStorage.getItem("role");

  return (
    <div
      style={{
        width: "220px",
        background: "#000",
        color: "white",
        height: "100vh",
        padding: "30px 20px",
      }}
    >

      <h2 style={{ marginBottom: "40px" }}>PlaceHub</h2>

      <ul style={{ listStyle: "none", padding: 0 }}>

        {/* 🔥 STUDENT ONLY */}
        {role === "student" && (
          <>
            <li><Link to="/predict" className="sidebar-link">AI Predictor</Link>
</li>

<li>
  <Link to="/resume" className="sidebar-link">Resume Help</Link>
</li>
          </>
        )}

        {/* 🔥 FACULTY */}
        {role === "faculty" && (
          <>
            <li><Link to="/dashboard">Dashboard</Link></li>
            <li><Link to="/students">Students</Link></li>
            <li><Link to="/analytics">Analytics</Link></li>
            <li><Link to="/predict">AI Predictor</Link></li>
            <li><Link to="/resume">Resume Help</Link></li>
          </>
        )}

        {/* 🔥 TPO (FULL ACCESS) */}
        {role === "tpo" && (
          <>
            <li><Link to="/dashboard">Dashboard</Link></li>
            <li><Link to="/students">Students</Link></li>
            <li><Link to="/add">Add Student</Link></li>
            <li><Link to="/analytics">Analytics</Link></li>
            <li><Link to="/predict">AI Predictor</Link></li>
            <li><Link to="/resume">Resume Help</Link></li>
          </>
        )}

      </ul>

    </div>
  );
}

export default Sidebar;
